#include <stdio.h>
#define MOD 1000000007
int main() {
    int Q, K, A, P;
    scanf("%d %d %d %d", &K, &A, &P, &Q);
    while (Q--) {
        int L, D, T;
        scanf("%d %d %d", &L, &D, &T);
        long long ans = 0;
        for (int i = 0; i < T; i++) {
            long long plans = 0;
            for (int j = 1; j <= K; j++) {
                if (j == 1) plans = L;
                else plans = (plans * (D + i + A - 1)) % P;
            }
            ans = (ans + plans) % P;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

